271:     private void maybeAddNodeForOptimizationMetadata(final GraphNode node) {
272:         node.setBuildPriority(buildPriorityIndex.getAndIncrement());
273: 
274:         if (node.parentNodes().isEmpty() && !node.nodeName().equals(TOPOLOGY_ROOT)) {
275:             throw new IllegalStateException(
276:                 "Nodes should not have a null parent node.  Name: " + node.nodeName() + " Type: "
277:                 + node.getClass().getSimpleName());
278:         }
279: 
280:         if (node.isKeyChangingOperation()) {
281:             keyChangingOperationsToOptimizableRepartitionNodes.put(node, new LinkedHashSet<>());
282:         } else if (node instanceof OptimizableRepartitionNode) {
283:             final GraphNode parentNode = getKeyChangingParentNode(node);
284:             if (parentNode != null) {
285:                 keyChangingOperationsToOptimizableRepartitionNodes.get(parentNode).add((OptimizableRepartitionNode<?, ?>) node);
286:             }
287:         } else if (node.isMergeNode()) {
288:             mergeNodes.add(node);
289:         } else if (node instanceof TableSourceNode) {
290:             tableSourceNodes.add(node);
291:         }
292:     }
