294:     private void maybeAddNodeForVersionedSemanticsMetadata(final GraphNode node) {
295:         if (node instanceof VersionedSemanticsGraphNode) {
296:             versionedSemanticsNodes.add(node);
297:         }
298:         if (node instanceof TableSuppressNode) {
299:             tableSuppressNodesNodes.add((TableSuppressNode<?, ?>) node);
300:         }
301:     }
