308:     public void buildAndOptimizeTopology(final Properties props) {
309:         mergeDuplicateSourceNodes();
310:         optimizeTopology(props);
311:         enableVersionedSemantics();
312: 
313:         final PriorityQueue<GraphNode> graphNodePriorityQueue = new PriorityQueue<>(5, Comparator.comparing(GraphNode::buildPriority));
314: 
315:         graphNodePriorityQueue.offer(root);
316: 
317:         while (!graphNodePriorityQueue.isEmpty()) {
318:             final GraphNode streamGraphNode = graphNodePriorityQueue.remove();
319: 
320:             if (LOG.isDebugEnabled()) {
321:                 LOG.debug("Adding nodes to topology {} child nodes {}", streamGraphNode, streamGraphNode.children());
322:             }
323: 
324:             if (streamGraphNode.allParentsWrittenToTopology() && !streamGraphNode.hasWrittenToTopology()) {
325:                 streamGraphNode.writeToTopology(internalTopologyBuilder);
326:                 streamGraphNode.setHasWrittenToTopology(true);
327:             }
328: 
329:             for (final GraphNode graphNode : streamGraphNode.children()) {
330:                 graphNodePriorityQueue.offer(graphNode);
331:             }
332:         }
333:         internalTopologyBuilder.validateCopartition();
334: 
335:         internalTopologyBuilder.checkUnprovidedNames();
336: 
337:     }
