293:     // Map from topics to their matched regex patterns, this is to ensure one topic is passed through on source node
294:     // even if it can be matched by multiple regex patterns. Only used by SourceNodeFactory
295:     private final Map<String, Pattern> topicToPatterns = new HashMap<>();
296: 
297:     private class SourceNodeFactory<KIn, VIn> extends NodeFactory<KIn, VIn, KIn, VIn> {
298:         private final List<String> topics;
299:         private final Pattern pattern;
300:         private final Deserializer<KIn> keyDeserializer;
301:         private final Deserializer<VIn> valDeserializer;
302:         private final TimestampExtractor timestampExtractor;
303: 
304:         private SourceNodeFactory(final String name,
305:                                   final String[] topics,
306:                                   final Pattern pattern,
307:                                   final TimestampExtractor timestampExtractor,
308:                                   final Deserializer<KIn> keyDeserializer,
309:                                   final Deserializer<VIn> valDeserializer) {
310:             super(name, NO_PREDECESSORS);
311:             this.topics = topics != null ? Arrays.asList(topics) : new ArrayList<>();
312:             this.pattern = pattern;
313:             this.keyDeserializer = keyDeserializer;
314:             this.valDeserializer = valDeserializer;
315:             this.timestampExtractor = timestampExtractor;
316:         }
317: 
318:         List<String> topics(final Collection<String> subscribedTopics) {
319:             // if it is subscribed via patterns, it is possible that the topic metadata has not been updated
320:             // yet and hence the map from source node to topics is stale, in this case we put the pattern as a place holder;
321:             // this should only happen for debugging since during runtime this function should always be called after the metadata has updated.
322:             if (subscribedTopics.isEmpty()) {
323:                 return Collections.singletonList(String.valueOf(pattern));
324:             }
325: 
326:             final List<String> matchedTopics = new ArrayList<>();
327:             for (final String update : subscribedTopics) {
328:                 if (pattern == topicToPatterns.get(update)) {
329:                     matchedTopics.add(update);
330:                 } else if (topicToPatterns.containsKey(update) && isMatch(update)) {
331:                     // the same topic cannot be matched to more than one pattern
332:                     // TODO: we should lift this requirement in the future
333:                     throw new TopologyException("Topic " + update +
334:                         " is already matched for another regex pattern " + topicToPatterns.get(update) +
335:                         " and hence cannot be matched to this regex pattern " + pattern + " any more.");
336:                 } else if (isMatch(update)) {
337:                     topicToPatterns.put(update, pattern);
338:                     matchedTopics.add(update);
339:                 }
340:             }
341:             return matchedTopics;
342:         }
343: 
344:         @Override
345:         public ProcessorNode<KIn, VIn, KIn, VIn> build() {
346:             return new SourceNode<>(name, timestampExtractor, keyDeserializer, valDeserializer);
347:         }
348: 
349:         private boolean isMatch(final String topic) {
350:             return pattern.matcher(topic).matches();
351:         }
352: 
353:         @Override
354:         Source describe() {
355:             return new Source(name, topics.isEmpty() ? null : new HashSet<>(topics), pattern);
356:         }
357:     }
