700:     private void validateTopicNotAlreadyRegistered(final String topic) {
701:         if (rawSourceTopicNames.contains(topic) || globalTopics.contains(topic)) {
702:             throw new TopologyException("Topic " + topic + " has already been registered by another source.");
703:         }
704: 
705:         for (final Pattern pattern : nodeToSourcePatterns.values()) {
706:             if (pattern.matcher(topic).matches()) {
707:                 throw new TopologyException("Topic " + topic + " matches a Pattern already registered by another source.");
708:             }
709:         }
710:     }
