1080:     private void initializeTopology() {
1081:         // initialize the task by initializing all its processor nodes in the topology
1082:         log.trace("Initializing processor nodes of the topology");
1083:         for (final ProcessorNode<?, ?, ?, ?> node : topology.processors()) {
1084:             processorContext.setCurrentNode(node);
1085:             try {
1086:                 node.init(processorContext, processingExceptionHandler);
1087:             } finally {
1088:                 processorContext.setCurrentNode(null);
1089:             }
1090:         }
1091:     }
