1093:     /**
1094:      * Adds records to queues. If a record has an invalid (i.e., negative) timestamp, the record is skipped
1095:      * and not added to the queue for processing
1096:      *
1097:      * @param partition the partition
1098:      * @param records   the records
1099:      */
1100:     @Override
1101:     public void addRecords(final TopicPartition partition, final Iterable<ConsumerRecord<byte[], byte[]>> records) {
1102:         final int newQueueSize = partitionGroup.addRawRecords(partition, records);
1103: 
1104:         if (log.isTraceEnabled()) {
1105:             log.trace("Added records into the buffered queue of partition {}, new queue size is {}", partition, newQueueSize);
1106:         }
1107: 
1108:         // if after adding these records, its partition queue's buffered size has been
1109:         // increased beyond the threshold, we can then pause the consumption for this partition
1110:         if (newQueueSize > maxBufferedSize) {
1111:             mainConsumer.pause(singleton(partition));
1112:         }
1113:     }
