56:                              final Map<String, Optional<InternalTopologyBuilder.ReprocessFactory<?, ?, ?, ?>>> storeNameToReprocessOnRestore) {
57:         this.processorNodes = Collections.unmodifiableList(processorNodes);
58:         this.sourceNodesByTopic = new HashMap<>(sourceNodesByTopic);
59:         this.sinksByTopic = Collections.unmodifiableMap(sinksByTopic);
60:         this.stateStores = Collections.unmodifiableList(stateStores);
61:         this.globalStateStores = Collections.unmodifiableList(globalStateStores);
62:         this.storeToChangelogTopic = Collections.unmodifiableMap(storeToChangelogTopic);
63:         this.repartitionTopics = Collections.unmodifiableSet(repartitionTopics);
64:         this.storeNameToReprocessOnRestore = storeNameToReprocessOnRestore;
65: 
66:         this.terminalNodes = new HashSet<>();
67:         for (final ProcessorNode<?, ?, ?, ?> node : processorNodes) {
68:             if (node.isTerminalNode()) {
69:                 terminalNodes.add(node.name());
70:             }
71:         }
72: 
73:         this.sourceNodesByName = new HashMap<>();
74:         for (final SourceNode<?, ?> source : sourceNodesByTopic.values()) {
75:             sourceNodesByName.put(source.name(), source);
76:         }
77:     }
