31: public class StreamSourceNode<K, V> extends SourceGraphNode<K, V> {
32: 
33:     private static final Logger log = LoggerFactory.getLogger(StreamSourceNode.class);
34: 
35:     public StreamSourceNode(final String nodeName,
36:                             final Collection<String> topicNames,
37:                             final ConsumedInternal<K, V> consumedInternal) {
38:         super(nodeName, topicNames, consumedInternal);
39:     }
40: 
41:     public StreamSourceNode(final String nodeName,
42:                             final Pattern topicPattern,
43:                             final ConsumedInternal<K, V> consumedInternal) {
44: 
45:         super(nodeName, topicPattern, consumedInternal);
46:     }
47: 
48:     public void merge(final StreamSourceNode<?, ?> other) {
49:         final AutoOffsetReset resetPolicy = consumedInternal().offsetResetPolicy();
50:         final AutoOffsetReset otherResetPolicy = other.consumedInternal().offsetResetPolicy();
51:         if (resetPolicy != null && !resetPolicy.equals(otherResetPolicy)
52:             || otherResetPolicy != null && !otherResetPolicy.equals(resetPolicy)) {
53:             log.error("Tried to merge source nodes {} and {} which are subscribed to the same topic/pattern, but "
54:                           + "the offset reset policies do not match", this, other);
55:             throw new TopologyException("Can't configure different offset reset policies on the same input topic(s)");
56:         }
57:         for (final GraphNode otherChild : other.children()) {
58:             other.removeChild(otherChild);
59:             addChild(otherChild);
60:         }
61:     }
62: 
63:     @Override
64:     public String toString() {
65:         return "StreamSourceNode{" +
66:                "topicNames=" + (topicNames().isPresent() ? topicNames().get() : null) +
67:                ", topicPattern=" + (topicPattern().isPresent() ? topicPattern().get() : null) +
68:                ", consumedInternal=" + consumedInternal() +
69:                "} " + super.toString();
70:     }
71: 
72:     @Override
73:     public void writeToTopology(final InternalTopologyBuilder topologyBuilder) {
74: 
75:         if (topicPattern().isPresent()) {
76:             topologyBuilder.addSource(consumedInternal().offsetResetPolicy(),
77:                                       nodeName(),
78:                                       consumedInternal().timestampExtractor(),
79:                                       consumedInternal().keyDeserializer(),
80:                                       consumedInternal().valueDeserializer(),
81:                                       topicPattern().get());
82:         } else {
83:             topologyBuilder.addSource(consumedInternal().offsetResetPolicy(),
84:                                       nodeName(),
85:                                       consumedInternal().timestampExtractor(),
86:                                       consumedInternal().keyDeserializer(),
87:                                       consumedInternal().valueDeserializer(),
88:                                       topicNames().get().toArray(new String[0]));
89:         }
90:     }
91: 
92: }
